// ═══════════════════════════════════════════════════════════════
// NODO: StepIsolator
// DESC: Estrae solo i dettagli dello step specifico dal Blueprint
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero Blueprint e ID dello step dal webhook
const blueprint = item.Blueprint || {};
const targetStepId = item.user_request.step_id;

let currentStep = null;

// 2. Ricerca ricorsiva dello step nei vari stage
if (blueprint.stages && Array.isArray(blueprint.stages)) {
    for (const stage of blueprint.stages) {
        if (stage.steps && Array.isArray(stage.steps)) {
            const found = stage.steps.find(s => s.step_id === targetStepId);
            if (found) {
                currentStep = found;
                break; 
            }
        }
    }
}

// 3. Gestione errore (se lo step non esiste nel blueprint)
if (!currentStep) {
    return [{
        json: {
            ...item,
            error: "STEP_NOT_FOUND",
            error_details: `Lo step ${targetStepId} non è stato trovato nel blueprint ${item.user_request.sop_id}`
        }
    }];
}

// 4. Output pulito: passiamo solo lo step essenziale
return [{
    json: {
        ...item,
        current_step_details: {
            step_name: currentStep.step_name,
            instructions: currentStep.instructions,
            evidence_type: currentStep.quality_check.evidence_type,
            check_description: currentStep.quality_check.check_description,
            acceptance_criteria: currentStep.quality_check.acceptance_criteria
        }
    }
}];
